" Custom field annotation — auto-generated when custom field is created
" The CFEND app generates this automatically:

@EndUserText.label: 'Custom Field: Sales Rep Commission'
@UI.lineItem: [{ position: 90, label: 'Commission %' }]
@Search.searchable: false
extend view I_SalesOrder with Z_I_SO_CustomFields
{
  @Semantics.quantity.unitOfMeasure: 'CurrencyCode'
  Z_Custom_CommissionPct : abap.dec(5,2);
}

" Custom Logic BAdI — auto-generated from key user app
" (not visible to key user, but this is what runs)
CLASS zcl_customlogic_approval IMPLEMENTATION.
  METHOD if_salesorder_badi~validate.
    IF is_header-Z_Custom_CommissionPct > 10.
      " Trigger approval workflow for VP
      APPEND INITIAL LINE TO et_messages ASSIGNING FIELD-SYMBOL(<msg>).
      <msg>-msgty = 'E'.
      <msg>-msgid = 'Z_SO'.
      <msg>-msgno = '001'.
    ENDIF.
  ENDMETHOD.
ENDCLASS.
